// kilodash polls this ~every 2s. Values/labels come from FLOW CONTEXT so any
// other node can feed a field just by writing flow.f1 .. flow.f4 (and, if you
// want a custom name, flow.f1_label .. flow.f4_label). Same for button labels.
const label = (k, d) => flow.get(k) ?? d;
const value = (k) => { const v = flow.get(k); return (v === undefined || v === null) ? '\u2014' : v; };
msg.payload = {
    fields: [
        { label: label('f1_label', 'Field 1'), value: value('f1') },
        { label: label('f2_label', 'Field 2'), value: value('f2') },
        { label: label('f3_label', 'Field 3'), value: value('f3') },
        { label: label('f4_label', 'Field 4'), value: value('f4') }
    ],
    buttons: [
        { label: label('b1_label', 'Trigger 1') },
        { label: label('b2_label', 'Trigger 2') },
        { label: label('b3_label', 'Trigger 3') },
        { label: label('b4_label', 'Trigger 4') }
    ]
};
return msg;

// Fired when a kilodash panel button is tapped. msg.req.params.n is '1'..'4'.
const n = msg.req.params.n;
node.warn('kilodash trigger ' + n);
// TODO: branch on n and do your action, e.g.:
//   if (n === '1') { /* toggle a GPIO, send MQTT, etc. */ }
msg.payload = { ok: true, btn: n };
return msg;

// Example: label Field 1 'Clock' and feed it a live value.
flow.set('f1_label', 'Clock');
flow.set('f1', new Date().toLocaleTimeString());
return null;
